return await (async function(eda) {
  const fixtureName = '__codex_example___ISCH_PrimitiveBus_toAsync_' + Date.now();
  const currentDocument = await eda.dmt_SelectControl.getCurrentDocumentInfo();
  if (!currentDocument) {
    throw new Error('当前没有活动文档，先打开一个可操作的文档页。');
  }
  if (currentDocument.documentType !== 1) {
    throw new Error('当前文档类型不是 SCHEMATIC_PAGE，请先切到 原理图图页 再运行这个案例。');
  }
  const selectedPrimitiveIds = eda.sch_SelectControl.getAllSelectedPrimitives_PrimitiveId();
  const primitiveId = Array.isArray(selectedPrimitiveIds) ? selectedPrimitiveIds[0] : undefined;
  if (!primitiveId) {
    throw new Error('请先在原理图画布上选中一个与 ISCH_PrimitiveBus 匹配的图元，再运行这个案例。');
  }
  const fetched = await eda.sch_PrimitiveBus.get([primitiveId]);
  const primitive = Array.isArray(fetched) ? fetched[0] : fetched;
  if (!primitive) { throw new Error('没有取到目标图元对象。'); }
  const result = await primitive.toAsync();
  return { fixtureName, primitiveId, result };
})(eda);
